// ============================================================
//  DRACHENGRAFIK
//  Zeichenflaeche: 760 x 356 (= Innenmass des Astlochs, LOCH in holz.js)
//
//  Die Koepfe kommen aus den Inkscape-Ebenen. Jede Ebene ist einzeln
//  eingefaerbt, nichts ist mehr durchscheinend. Das Auge liegt bei
//  jedem Drachen auf (470 | 165): waagerecht rechts der Lochmitte,
//  senkrecht ungefaehr mittig.
//
//  Aufbau:
//    <g class="dr-koerper" transform="translate(tx ty) scale(s)">
//        ... Koerperteile, jede in ihrer Farbe ...
//        <g class="dr-auge-auf" transform="translate(cx cy)">
//          <g class="dr-blinzel">      <- nur das blinzelt
//             Lederhaut, Pupille, Lichtpunkt
//
//  Nachjustieren: translate/scale in der jeweiligen Konstante aendern.
//  Die Augen wandern mit, ihre Mittelpunkte stehen im Zeichnungssystem.
// ============================================================
// Kringel — wird von spiel.js fuer die Glasmuster gebraucht
export function kringel(x, y, r, farbe, windungen = 2.2) {
  const schritte = 32;
  let d = '';
  for (let i = 0; i <= schritte; i++) {
    const t = i / schritte;
    const winkel = t * Math.PI * 2 * windungen;
    const radius = r * t;
    const px = (Math.cos(winkel) * radius).toFixed(1);
    const py = (Math.sin(winkel) * radius).toFixed(1);
    d += (i === 0 ? 'M' : 'L') + px + ' ' + py + ' ';
  }
  return `<path d="${d}" transform="translate(${x} ${y})" fill="none" ` +
    `stroke="${farbe}" stroke-width="${(r * 0.13).toFixed(1)}" stroke-linecap="round"/>`;
}

// Hilfsfunktion zum Generieren der Zähne
function zaehne(x1, y1, x2, y2, anzahl, hoehe) {
  let z = '';
  for (let i = 0; i < anzahl; i++) {
    const t = i / (anzahl - 1 || 1);
    const x = x1 + (x2 - x1) * t;
    const y = y1 + (y2 - y1) * t;
    z += `<polygon points="${x},${y} ${x + 6},${y + hoehe} ${x - 6},${y + hoehe}" fill="#e8e0d5"/>`;
  }
  return z;
}

